  \label{lem:modules_annihilator_ideal}
  \lean{AlgebraicGeometry.Scheme.Modules.annihilator_ideal}
  \uses{def:modules_annihilator, lem:modules_annihilator_ideal_le,
    lem:annihilator_localization_eq_map, lem:qcoh_section_localization_basicOpen}
  Let \(X\) be a scheme, \(\mathcal{F}\) a quasi-coherent sheaf of \(\mathcal{O}_X\)-modules
  with \(\mathcal{F}\) of finite type, and \(U \subseteq X\) an affine open. Then the section
  over \(U\) of the annihilator ideal sheaf \(\mathrm{Ann}(\mathcal{F})\)
  (\cref{def:modules_annihilator}) \emph{equals} the module-annihilator of the sections:
  \[
    \mathrm{Ann}(\mathcal{F})(U)
    \;=\; \mathrm{Ann}_{\mathcal{O}_X(U)}\bigl(\mathcal{F}(U)\bigr).
  \]
  The inclusion \(\subseteq\) is \cref{lem:modules_annihilator_ideal_le}; the reverse
  inclusion is the content here, now available since
  \cref{lem:qcoh_section_localization_basicOpen} is proved.
\end{lemma}
\begin{proof}
  \uses{lem:modules_annihilator_ideal_le, lem:annihilator_localization_eq_map,
    lem:qcoh_section_localization_basicOpen}
  Only the reverse inclusion remains. By construction
